{"code": "import json
import re

# Read all funding data
funding_file_path = locals()['var_functions.query_db:26']
with open(funding_file_path, 'r') as f:
    funding_data = json.load(f)

# Read all civic documents
civic_docs_file_path = locals()['var_functions.query_db:27']
with open(civic_docs_file_path, 'r') as f:
    civic_docs = json.load(f)

# Combine all text from civic documents for searching
all_text = " ".join([doc.get('text', '') for doc in civic_docs])

# Find projects related to 'emergency' or 'FEMA'
emergency_fema_projects = []
for project in funding_data:
    project_name = project['Project_Name']
    if 'emergency' in project_name.lower() or 'fema' in project_name.lower():
        emergency_fema_projects.append(project)

# Function to extract project status from text
def get_project_status(project_name, full_text):
    base_name = project_name.split('(')[0].strip()
    lower_text = full_text.lower()

    if base_name.lower() not in lower_text:
        return "Information not available"

    # Find position of the project in the text
    pos = lower_text.find(base_name.lower())
    context_window = 800  # Characters before and after
    context = full_text[max(0, pos-context_window):min(len(full_text), pos+context_window)]
    lower_context = context.lower()

    # Check for status indicators in context
    if re.search(r'(design|finalizing|working with consultant|preparation|development|pending approval)', lower_context, re.IGNORECASE):
        return "Design"

    if re.search(r'(construction|under construction|contract awarded|construction bid|contractor)', lower_context, re.IGNORECASE):
        if re.search(r'(completed|finished|notice of completion)', lower_context, re.IGNORECASE):
            return "Completed"
        return "Construction"

    if re.search(r'(completed|finished|notice of completion|council accepted|construction was completed)', lower_context, re.IGNORECASE):
        return "Completed"

    if re.search(r'(not started|future|identified|waiting|pending|delayed|application submitted|waiting for)', lower_context, re.IGNORECASE):
        return "Not Started"

    # Check section headers
    design_section = re.search(r'Disaster Projects \(Design\)|Capital Improvement Projects \(Design\)', lower_text)
    construction_section = re.search(r'Disaster Projects \(Construction\)|Capital Improvement Projects \(Construction\)', lower_text)
    completed_section = re.search(r'Disaster Projects \(Completed\)|Capital Improvement Projects \(Completed\)', lower_text)
    not_started_section = re.search(r'Disaster Projects \(Not Started\)|Capital Improvement Projects \(Not Started\)', lower_text)

    if design_section:
        design_pos = design_section.start()
        next_section_pos = len(lower_text)
        for section in [construction_section, completed_section, not_started_section]:
            if section and section.start() > design_pos:
                next_section_pos = min(next_section_pos, section.start())

        if design_pos < pos < next_section_pos:
            return "Design"

    if construction_section:
        construction_pos = construction_section.start()
        next_section_pos = len(lower_text)
        for section in [completed_section, not_started_section, design_section]:
            if section and section.start() > construction_pos:
                next_section_pos = min(next_section_pos, section.start())

        if construction_pos < pos < next_section_pos:
            return "Construction"

    if completed_section:
        completed_pos = completed_section.start()
        next_section_pos = len(lower_text)
        for section in [design_section, not_started_section, construction_section]:
            if section and section.start() > completed_pos:
                next_section_pos = min(next_section_pos, section.start())

        if completed_pos < pos < next_section_pos:
            return "Completed"

    if not_started_section:
        not_started_pos = not_started_section.start()
        next_section_pos = len(lower_text)
        for section in [design_section, construction_section, completed_section]:
            if section and section.start() > not_started_pos:
                next_section_pos = min(next_section_pos, section.start())

        if not_started_pos < pos < next_section_pos:
            return "Not Started"

    return "Information not available"

# Process each project
results = []
for project in emergency_fema_projects:
    project_name = project['Project_Name']
    funding_source = project['Funding_Source']
    amount = int(project['Amount'])
    status = get_project_status(project_name, all_text)

    results.append({
        'Project_Name': project_name,
        'Funding_Source': funding_source,
        'Amount': amount,
        'Status': status
    })

# Sort by amount descending
results.sort(key=lambda x: x['Amount'], reverse=True)

# Format amount for display
formatted_results = []
for r in results:
    formatted_results.append({
        'Project_Name': r['Project_Name'],
        'Funding_Source': r['Funding_Source'],
        'Amount': f"${r['Amount']:,}",
        'Status': r['Status']
    })

print('__RESULT__:')
print(json.dumps(formatted_results))"}

